source .venv/bin/activate && python3 << 'EOF'
import requests
import time

papers = {
    "2503.22444_scaling_laws_discovery": "https://arxiv.org/pdf/2503.22444",
    "2510.09901_autonomous_agents_discovery": "https://arxiv.org/pdf/2510.09901",
    "2401.04334_llm_robotics": "https://arxiv.org/pdf/2401.04334",
    "2502.03814_llm_multi_robot": "https://arxiv.org/pdf/2502.03814",
}

headers = {'User-Agent': 'Mozilla/5.0 (compatible; research-bot/1.0)'}

for name, url in papers.items():
    filepath = f"papers/{name}.pdf"
    print(f"Downloading {name}...")
    try:
        r = requests.get(url, headers=headers, timeout=60, allow_redirects=True)
        if r.status_code == 200 and len(r.content) > 1000:
            with open(filepath, 'wb') as f:
                f.write(r.content)
            size_kb = len(r.content) // 1024
            print(f"  OK: {filepath} ({size_kb} KB)")
        else:
            print(f"  FAILED: status={r.status_code}, size={len(r.content)}")
    except Exception as e:
        print(f"  ERROR: {e}")
    time.sleep(5)
EOF

